  ('medical-tech-moex-00973', 'medical-tech', 'medical-tech-moex-110-0356504f', 'sub-medical-tech-04', NULL, 'single_choice', '鼻病毒（Rhinovirus）感染常造成上呼吸道感染，也有可能造成嗅覺喪失，下列敘述何者錯誤？ A. 鼻病毒感染可以造成鼻竇炎和中耳炎', '["", "鼻病毒感染可以加重兒童氣喘", "核酸偵測技術可提高鼻病毒確診率", "C型鼻病毒很容易用人類細胞培養分離"]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:32+00:00", "source_pdf_sha1": "1bb92c6fe72d", "answer_pdf_sha1": "4c3901b6c95b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110020", "c": "308", "s": "66", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血清免疫學與臨床病毒學", "year": "110", "exam_name": "110年第一次專技人員高等考試醫師牙醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試", "original_question_number": 55, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
